import{_ as a,c as s,o as t,ag as i}from"./chunks/framework.Bzez9NG9.js";const n="/space/img/ai_assistant.png",m=JSON.parse('{"title":"AI Assistant","titleTemplate":"SPACE","description":"","frontmatter":{"outline":"deep","title":"AI Assistant","titleTemplate":"SPACE"},"headers":[],"relativePath":"doc/ai-assistant.md","filePath":"doc/ai-assistant.md"}'),o={name:"doc/ai-assistant.md"};function l(r,e,c,d,p,h){return t(),s("div",null,e[0]||(e[0]=[i('<h1 id="ai-assistant" tabindex="-1">AI Assistant <a class="header-anchor" href="#ai-assistant" aria-label="Permalink to &quot;AI Assistant&quot;">​</a></h1><p>The SPACE AI Assistant helps IBM Planning Analytics users understand SPACE functionality, inspect TM1 model objects, and get guided explanations directly inside IBM Planning Analytics Workspace.</p><p>Unlike a generic chatbot, the SPACE AI Assistant is designed to work inside the governed SPACE environment. It can use SPACE-controlled tools, respect user access, and provide answers based on the connected IBM Planning Analytics model.</p><p><img src="'+n+'" alt="SPACE overview" data-zoomable=""></p><h2 id="what-can-the-ai-assistant-help-with" tabindex="-1">What can the AI Assistant help with? <a class="header-anchor" href="#what-can-the-ai-assistant-help-with" aria-label="Permalink to &quot;What can the AI Assistant help with?&quot;">​</a></h2><p>The AI Assistant can help users:</p><ul><li>Ask questions about SPACE functionality</li><li>Find and understand TM1 objects</li><li>Explain cube rules and calculation logic</li><li>Review TurboIntegrator process code</li><li>Understand model structure and dependencies</li><li>Summarize technical logic in business-friendly language</li><li>Guide users through investigation and documentation workflows</li></ul><p>The assistant is especially useful when users need help understanding how a TM1 model works without manually searching through cubes, rules, processes, and documentation.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>The AI Assistant combines a conversational interface with SPACE tools.</p><p>When a user asks a question, SPACE can allow the assistant to use approved tools to inspect the connected model. For example, the assistant may retrieve a cube rule, inspect a process, search for model objects, or review available documentation before responding.</p><p>The assistant does not replace SPACE security. It operates through SPACE and follows the access available to the current user.</p><h2 id="example-questions" tabindex="-1">Example questions <a class="header-anchor" href="#example-questions" aria-label="Permalink to &quot;Example questions&quot;">​</a></h2><p>Users can ask questions such as:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>What does the Sales cube rule do?</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Explain the Load_GL_Actuals process.</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Find cubes related to actuals.</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>How do I compare two TM1 environments in SPACE?</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Which process updates the reporting cube?</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Summarize this model logic for a business user.</span></span></code></pre></div><h2 id="model-aware-assistance" tabindex="-1">Model-aware assistance <a class="header-anchor" href="#model-aware-assistance" aria-label="Permalink to &quot;Model-aware assistance&quot;">​</a></h2><p>When connected to an IBM Planning Analytics environment, the AI Assistant can help explain TM1 model objects such as:</p><ul><li>Cubes</li><li>Dimensions</li><li>Rules</li><li>Feeders</li><li>TurboIntegrator processes</li><li>Chores</li><li>Logs and audit information</li><li>Model documentation and dependency diagrams</li></ul><p>The assistant is most helpful when it can use structured model information from SPACE instead of relying only on a general language model response.</p><h2 id="space-documentation-help" tabindex="-1">SPACE documentation help <a class="header-anchor" href="#space-documentation-help" aria-label="Permalink to &quot;SPACE documentation help&quot;">​</a></h2><p>The AI Assistant can also help users understand how to use SPACE itself.</p><p>For example, users can ask about:</p><ul><li>Model documentation</li><li>Lifecycle management</li><li>Git integration</li><li>Python integration</li><li>Logs and audit</li><li>Security manager</li><li>Connection setup</li><li>AI Assistant behavior</li></ul><p>This helps users get answers without leaving IBM Planning Analytics Workspace.</p><h2 id="governed-access" tabindex="-1">Governed access <a class="header-anchor" href="#governed-access" aria-label="Permalink to &quot;Governed access&quot;">​</a></h2><p>The AI Assistant is designed to respect SPACE permissions and IBM Planning Analytics access controls.</p><p>Users should only be able to use tools and inspect objects they are allowed to access. Admin users can configure AI profiles, available models, and assistant behavior based on the deployment requirements.</p><h2 id="ai-profiles" tabindex="-1">AI profiles <a class="header-anchor" href="#ai-profiles" aria-label="Permalink to &quot;AI profiles&quot;">​</a></h2><p>SPACE AI profiles define how the assistant connects to an AI provider and how responses are generated.</p><p>AI profile settings may include:</p><ul><li>Provider</li><li>Model</li><li>Maximum input tokens</li><li>Maximum output tokens</li><li>Temperature</li><li>Connection credentials or provider configuration</li></ul><p>If token or temperature fields are left empty, SPACE uses its configured defaults.</p><h2 id="conversation-memory" tabindex="-1">Conversation memory <a class="header-anchor" href="#conversation-memory" aria-label="Permalink to &quot;Conversation memory&quot;">​</a></h2><p>The AI Assistant can maintain conversation context so users can ask follow-up questions.</p><p>For longer conversations, SPACE may summarize older messages into compact conversation memory. This helps keep the assistant responsive while preserving the important context from earlier parts of the conversation.</p><p>Original messages remain stored in SPACE. Compaction only changes what is sent back to the AI model for future context.</p><h2 id="markdown-responses" tabindex="-1">Markdown responses <a class="header-anchor" href="#markdown-responses" aria-label="Permalink to &quot;Markdown responses&quot;">​</a></h2><p>Assistant responses support Markdown formatting, including:</p><ul><li>Headings</li><li>Lists</li><li>Tables</li><li>Inline code</li><li>Code blocks</li><li>Links</li></ul><p>This makes technical explanations, rule summaries, process reviews, and documentation-style responses easier to read.</p><h2 id="recommended-usage" tabindex="-1">Recommended usage <a class="header-anchor" href="#recommended-usage" aria-label="Permalink to &quot;Recommended usage&quot;">​</a></h2><p>Use the AI Assistant for guided analysis and explanation.</p><p>For example:</p><ol><li>Ask a broad question about a cube, process, or SPACE feature.</li><li>Review the assistant’s summary.</li><li>Ask follow-up questions about specific sections.</li><li>Use SPACE tools and documentation for validation when needed.</li></ol><p>The assistant is best used as a productivity and explanation layer on top of SPACE, not as a replacement for governed review and testing.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><p>The AI Assistant may not always have enough information to answer every question. If the model structure is ambiguous, the assistant may ask for clarification or explain its assumptions.</p><p>For critical changes, users should still validate results through SPACE, IBM Planning Analytics, and standard review processes.</p>',53)]))}const g=a(o,[["render",l]]);export{m as __pageData,g as default};
